INSERT INTO MSF_REQUEST_STATE (
      REQUEST_STATE_KEY
    , REQUEST_STATE_CODE
    , DLVRY_NO
    , OPEN_NO
    , MEMO
    , SYS_RDATE
    , RIP
    , RID
    , VIEW_FLAG
    , RES_NO
    , REQUEST_KEY
    , TB_CD
) VALUES (
      nextval('SQ_REQUEST_STATE_SEQ')
    , #{requestStateCode}
    , #{dlvryNo}
    , #{openNo}
    , #{memo}
    , NOW()
    , #{rip}
    , #{rid}
    , #{viewFlag}
    , #{resNo}
    , #{requestKey}
    , #{tbCd}
)

mapper.update:
UPDATE MSF_REQUEST_STATE
SET RVISN_DTTM = NOW()

    , REQUEST_STATE_CODE = #{requestStateCode}


    , VIEW_FLAG = #{viewFlag}

WHERE REQUEST_KEY = #{requestKey}

